storable_contract.code:
// Модель ОБЯЗАНА реализовывать соответствующий интерфейс
class WorkflowGraph implements VersionedStorable {
  static const String kCollection = 'workflow_graphs';
  static final _WorkflowGraphKeys _keys = _WorkflowGraphKeys._();
  static _WorkflowGraphKeys get keys => _keys;

  @override
  String get id => _id;

  @override
  String get tenantId => _tenantId;

  @override
  bool get softDelete => false; // VersionedStorable требует это поле

  @override
  Map<String, dynamic> toMap() => {
    WorkflowGraph.keys.id: _id,
    WorkflowGraph.keys.tenantId: _tenantId,
    // ... остальные поля через keys
  };

  static WorkflowGraph fromMap(Map<String, dynamic> map) => WorkflowGraph(
    id: map[WorkflowGraph.keys.id] as String,
    // ...
  );
}

registration_pattern.code:
// ✅ ПРАВИЛЬНО — серверная инициализация
final registry = VaultRegistry(
  storageFactory: (tenantId) => PostgresVaultStorage(
    pool: pool,
    tenantId: tenantId,
  ),
  deployer: PostgresSchemaDeployer(pool: pool),
);

// Регистрация доменов из aq_schema
registry
  ..register(DomainRegistration(
    collection: WorkflowGraph.kCollection,
    mode: StorageMode.versioned,
    fromMap: WorkflowGraph.fromMap,
    jsonSchema: WorkflowGraph.kJsonSchema,
    schemaVersion: WorkflowGraph.kSchemaVersion,
  ))
  ..register(DomainRegistration(
    collection: AqStudioProject.kCollection,
    mode: StorageMode.direct,
    fromMap: AqStudioProject.fromMap,
    jsonSchema: AqStudioProject.kJsonSchema,
  ))
  ..register(DomainRegistration(
    collection: WorkflowRun.kCollection,
    mode: StorageMode.logged,
    fromMap: WorkflowRun.fromMap,
  ));

await registry.deploy(); // Создаёт таблицы

security_protocol.initialization:
// В точке сборки (main.dart)
IVaultSecurityProtocol.initialize(
  AqVaultSecurityProtocol(securityService: ISecurityService.instance)
);

infrastructure_interfaces.initialization:
// dart_vault при старте регистрирует все три
void initializeInfrastructure() {
  ISecretsManager.initialize(VaultSecretsManager());
  IBackupService.initialize(VaultBackupService());
  IDatabaseHardening.initialize(PostgresHardening());
}

client_usage.pattern:
// ✅ Клиент подключается и получает репозиторий
await Vault.connect('http://localhost:8765');

final workflows = Vault.instance.versioned<WorkflowGraph>(
  collection: WorkflowGraph.kCollection,
  fromMap: WorkflowGraph.fromMap,
);

// Работа с репозиторием
final node = await workflows.createEntity(myWorkflow);
final list = await workflows.listEntities(tenantId: 'user-123');
await workflows.publishEntity(entityId: node.entityId);

pattern.code:
// ❌ ЗАПРЕЩЕНО — локальная модель в registry
registry.register(DomainRegistration(
  collection: 'my_local_collection',
  fromMap: MyLocalModel.fromMap, // ❌ не из aq_schema
));

// ❌ ЗАПРЕЩЕНО — хардкод имени коллекции
final repo = vault.versioned(collection: 'workflow_graphs', ...); // ❌

// ✅ ПРАВИЛЬНО
final repo = vault.versioned(collection: WorkflowGraph.kCollection, ...); // ✅

// ❌ ЗАПРЕЩЕНО — логика безопасности внутри vault
class PostgresVaultStorage {
  Future<void> write(String key, value) async {
    if (user.role == 'admin') { ... } // ❌ Роли — не компетенция vault
  }
}

// ✅ ПРАВИЛЬНО — делегировать через protocol
class PostgresVaultStorage {
  Future<void> write(String key, value, Map<String, String> headers) async {
    final claims = await IVaultSecurityProtocol.instance.extractClaims(headers);
    final decision = await IVaultSecurityProtocol.instance.canWrite(
      claims: claims, collection: key, data: value,
    );
    if (decision is AccessDenied) throw SecurityException(decision.reason);
    // ... сохранить
  }
}

// ❌ ЗАПРЕЩЕНО — storage в клиентском экспорте
// lib/dart_vault.dart
export 'storage/postgres_vault_storage.dart'; // ❌ Storage только на сервере!

// ✅ ПРАВИЛЬНО
// lib/dart_vault.dart — только клиент
export 'client/vault.dart';
// lib/server.dart — сервер
export 'storage/postgres_vault_storage.dart';
